  1→/**
  2→ * Product Service
  3→ *
  4→ * Handles API calls for products overview functionality
  5→ *
  6→ * Feature: 054-products-overview
  7→ */
  8→
  9→import { authenticatedGet } from '../utils/auth';
 10→
 11→export interface ProductListResponse {
 12→    products: string[];
 13→    totalCount: number;
 14→}
 15→
 16→export interface ProductSystemDto {
 17→    assetId: number;
 18→    name: string;
 19→    ip: string | null;
 20→    adDomain: string | null;
 21→}
 22→
 23→export interface PaginatedProductSystemsResponse {
 24→    content: ProductSystemDto[];
 25→    totalElements: number;
 26→    totalPages: number;
 27→    currentPage: number;
 28→    pageSize: number;
 29→    hasNext: boolean;
 30→    hasPrevious: boolean;
 31→    productName: string;
 32→}
 33→
 34→export interface TopProductDto {
 35→    product: string;
 36→    vulnerabilityCount: number;
 37→}
 38→
 39→export interface TopProductsResponse {
 40→    products: TopProductDto[];
 41→    totalCount: number;
 42→}
 43→
 44→/**
 45→ * Get top products by vulnerability count
 46→ *
 47→ * @param limit Maximum number of products to return (default 15)
 48→ * @returns Promise<TopProductsResponse>
 49→ */
 50→export async function getTopProducts(limit: number = 15): Promise<TopProductsResponse> {
 51→    const params = new URLSearchParams();
 52→    params.append('limit', limit.toString());
 53→
 54→    const url = `/api/products/top?${params.toString()}`;
 55→    const response = await authenticatedGet(url);
 56→
 57→    if (!response.ok) {
 58→        throw new Error(`Failed to fetch top products: ${response.status}`);
 59→    }
 60→    return response.json();
 61→}
 62→
 63→/**
 64→ * Get list of unique products from vulnerability data
 65→ * Task: T012, T022 (search support)
 66→ *
 67→ * @param search Optional search term for filtering products
 68→ * @returns Promise<ProductListResponse>
 69→ */
 70→export async function getProducts(search?: string): Promise<ProductListResponse> {
 71→    const params = new URLSearchParams();
 72→    if (search && search.trim()) {
 73→        params.append('search', search.trim());
 74→    }
 75→
 76→    const queryString = params.toString();
 77→    const url = queryString ? `/api/products?${queryString}` : '/api/products';
 78→
 79→    const response = await authenticatedGet(url);
 80→    if (!response.ok) {
 81→        throw new Error(`Failed to fetch products: ${response.status}`);
 82→    }
 83→    return response.json();
 84→}
 85→
 86→/**
 87→ * Get paginated list of systems running a specific product
 88→ * Task: T012
 89→ *
 90→ * @param product - Product name (will be URL encoded)
 91→ * @param page - Page number (0-indexed)
 92→ * @param size - Page size (default 50)
 93→ * @returns Promise<PaginatedProductSystemsResponse>
 94→ */
 95→export async function getProductSystems(
 96→    product: string,
 97→    page: number = 0,
 98→    size: number = 50
 99→): Promise<PaginatedProductSystemsResponse> {
100→    const encodedProduct = encodeURIComponent(product);
101→    const params = new URLSearchParams();
102→    params.append('page', page.toString());
103→    params.append('size', size.toString());
104→
105→    const url = `/api/products/${encodedProduct}/systems?${params.toString()}`;
106→    const response = await authenticatedGet(url);
107→
108→    if (!response.ok) {
109→        throw new Error(`Failed to fetch product systems: ${response.status}`);
110→    }
111→    return response.json();
112→}
113→
114→/**
115→ * Export systems running a specific product to Excel
116→ * Task: T028
117→ *
118→ * @param product - Product name (will be URL encoded)
119→ * @returns Promise<void> - Downloads the Excel file
120→ */
121→export async function exportProductSystems(product: string): Promise<void> {
122→    const encodedProduct = encodeURIComponent(product);
123→    const url = `/api/products/${encodedProduct}/export`;
124→
125→    // Use fetch with credentials to include HttpOnly auth cookie
126→    const response = await fetch(url, {
127→        method: 'GET',
128→        credentials: 'include'
129→    });
130→
131→    if (!response.ok) {
132→        // Try to get error message from response body
133→        let errorMessage = `Failed to export product systems: ${response.status}`;
134→        try {
135→            const errorBody = await response.json();
136→            if (errorBody.error) {
137→                errorMessage = errorBody.error;
138→            }
139→        } catch {
140→            // Ignore JSON parse error, use default message
141→        }
142→        throw new Error(errorMessage);
143→    }
144→
145→    // Get filename from Content-Disposition header or use default
146→    const contentDisposition = response.headers.get('Content-Disposition');
147→    let filename = 'product_systems_export.xlsx';
148→    if (contentDisposition) {
149→        const match = contentDisposition.match(/filename="([^"]+)"/);
150→        if (match) {
151→            filename = match[1];
152→        }
153→    }
154→
155→    // Create blob and trigger download
156→    const blob = await response.blob();
157→    const downloadUrl = window.URL.createObjectURL(blob);
158→    const link = document.createElement('a');
159→    link.href = downloadUrl;
160→    link.download = filename;
161→    document.body.appendChild(link);
162→    link.click();
163→    document.body.removeChild(link);
164→    window.URL.revokeObjectURL(downloadUrl);
165→}
