  1→/**
  2→ * ProductsOverview Component
  3→ *
  4→ * Displays products from vulnerability data with systems list
  5→ * Features:
  6→ * - Product dropdown selector with search filter
  7→ * - Paginated systems table
  8→ * - Empty state handling
  9→ *
 10→ * Feature: 054-products-overview
 11→ * Task: T013-T015, T023-T024 (search)
 12→ * User Story: US1 - View Systems Running a Specific Product (P1)
 13→ * User Story: US2 - Search and Filter Products (P2)
 14→ */
 15→
 16→import React, { useState, useEffect, useRef, useCallback } from 'react';
 17→import {
 18→    getProducts,
 19→    getProductSystems,
 20→    exportProductSystems,
 21→    getTopProducts,
 22→    type ProductListResponse,
 23→    type PaginatedProductSystemsResponse,
 24→    type ProductSystemDto,
 25→    type TopProductDto
 26→} from '../services/productService';
 27→
 28→const ProductsOverview: React.FC = () => {
 29→    // Product list state
 30→    const [products, setProducts] = useState<string[]>([]);
 31→    const [selectedProduct, setSelectedProduct] = useState<string>('');
 32→    const [loadingProducts, setLoadingProducts] = useState<boolean>(true);
 33→
 34→    // Top products state
 35→    const [topProducts, setTopProducts] = useState<TopProductDto[]>([]);
 36→    const [loadingTopProducts, setLoadingTopProducts] = useState<boolean>(true);
 37→
 38→    // Search state
 39→    const [searchTerm, setSearchTerm] = useState<string>('');
 40→    const [debouncedSearch, setDebouncedSearch] = useState<string>('');
 41→    const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null);
 42→
 43→    // Systems state
 44→    const [systems, setSystems] = useState<ProductSystemDto[]>([]);
 45→    const [loadingSystems, setLoadingSystems] = useState<boolean>(false);
 46→
 47→    // Pagination state
 48→    const [currentPage, setCurrentPage] = useState<number>(0);
 49→    const [pageSize, setPageSize] = useState<number>(50);
 50→    const [totalPages, setTotalPages] = useState<number>(0);
 51→    const [totalElements, setTotalElements] = useState<number>(0);
 52→
 53→    // Error state
 54→    const [error, setError] = useState<string | null>(null);
 55→
 56→    // Export state
 57→    const [exporting, setExporting] = useState<boolean>(false);
 58→
 59→    /**
 60→     * Debounce search input
 61→     */
 62→    useEffect(() => {
 63→        if (searchTimeoutRef.current) {
 64→            clearTimeout(searchTimeoutRef.current);
 65→        }
 66→
 67→        searchTimeoutRef.current = setTimeout(() => {
 68→            setDebouncedSearch(searchTerm);
 69→        }, 300);
 70→
 71→        return () => {
 72→            if (searchTimeoutRef.current) {
 73→                clearTimeout(searchTimeoutRef.current);
 74→            }
 75→        };
 76→    }, [searchTerm]);
 77→
 78→    /**
 79→     * Fetch products when debounced search changes
 80→     */
 81→    useEffect(() => {
 82→        fetchProducts(debouncedSearch);
 83→    }, [debouncedSearch]);
 84→
 85→    /**
 86→     * Fetch top products on mount
 87→     */
 88→    useEffect(() => {
 89→        fetchTopProducts();
 90→    }, []);
 91→
 92→    /**
 93→     * Fetch systems when product changes
 94→     */
 95→    useEffect(() => {
 96→        if (selectedProduct) {
 97→            fetchSystems();
 98→        } else {
 99→            setSystems([]);
100→            setTotalElements(0);
101→            setTotalPages(0);
102→        }
103→    }, [selectedProduct, currentPage, pageSize]);
104→
105→    /**
106→     * Fetch products list with optional search
107→     */
108→    const fetchProducts = async (search?: string) => {
109→        setLoadingProducts(true);
110→        setError(null);
111→
112→        try {
113→            const response: ProductListResponse = await getProducts(search);
114→            setProducts(response.products);
115→            // Clear selection if the selected product is no longer in the filtered list
116→            if (selectedProduct && !response.products.includes(selectedProduct)) {
117→                setSelectedProduct('');
118→            }
119→        } catch (err: any) {
120→            console.error('Failed to fetch products:', err);
121→            setError('Failed to load products. Please try again.');
122→        } finally {
123→            setLoadingProducts(false);
124→        }
125→    };
126→
127→    /**
128→     * Fetch top products by vulnerability count
129→     */
130→    const fetchTopProducts = async () => {
131→        setLoadingTopProducts(true);
132→
133→        try {
134→            const response = await getTopProducts(15);
135→            setTopProducts(response.products);
136→        } catch (err: any) {
137→            console.error('Failed to fetch top products:', err);
138→            // Don't set error for top products - just log it
139→        } finally {
140→            setLoadingTopProducts(false);
141→        }
142→    };
143→
144→    /**
145→     * Fetch systems for selected product
146→     */
147→    const fetchSystems = async () => {
148→        if (!selectedProduct) return;
149→
150→        setLoadingSystems(true);
151→        setError(null);
152→
153→        try {
154→            const response: PaginatedProductSystemsResponse = await getProductSystems(
155→                selectedProduct,
156→                currentPage,
157→                pageSize
158→            );
159→            setSystems(response.content);
160→            setTotalElements(response.totalElements);
161→            setTotalPages(response.totalPages);
162→        } catch (err: any) {
163→            console.error('Failed to fetch systems:', err);
164→            setError('Failed to load systems. Please try again.');
165→        } finally {
166→            setLoadingSystems(false);
167→        }
168→    };
169→
170→    /**
171→     * Handle product selection from dropdown
172→     */
173→    const handleProductChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
174→        setSelectedProduct(e.target.value);
175→        setCurrentPage(0); // Reset to first page when product changes
176→    };
177→
178→    /**
179→     * Handle product selection from top products list
180→     */
181→    const handleTopProductClick = (productName: string) => {
182→        setSelectedProduct(productName);
183→        setSearchTerm('');
184→        setCurrentPage(0);
185→    };
186→
187→    /**
188→     * Handle page change
189→     */
190→    const handlePageChange = (newPage: number) => {
191→        setCurrentPage(newPage);
192→    };
193→
194→    /**
195→     * Handle page size change
196→     */
197→    const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
198→        setPageSize(parseInt(e.target.value, 10));
199→        setCurrentPage(0); // Reset to first page
200→    };
201→
202→    /**
203→     * Handle export to Excel
204→     */
205→    const handleExport = async () => {
206→        if (!selectedProduct) return;
207→
208→        setExporting(true);
209→        setError(null);
210→
211→        try {
212→            await exportProductSystems(selectedProduct);
213→        } catch (err: any) {
214→            console.error('Failed to export systems:', err);
215→            setError(err.message || 'Failed to export systems. Please try again.');
216→        } finally {
217→            setExporting(false);
218→        }
219→    };
220→
221→    /**
222→     * Generate page numbers for pagination
223→     */
224→    const getPageNumbers = (): (number | string)[] => {
225→        const pages: (number | string)[] = [];
226→        const maxVisiblePages = 7;
227→
228→        if (totalPages <= maxVisiblePages) {
229→            for (let i = 0; i < totalPages; i++) {
230→                pages.push(i);
231→            }
232→        } else {
233→            // Always show first page
234→            pages.push(0);
235→
236→            if (currentPage > 2) {
237→                pages.push('...');
238→            }
239→
240→            // Show pages around current page
241→            const start = Math.max(1, currentPage - 1);
242→            const end = Math.min(totalPages - 2, currentPage + 1);
243→
244→            for (let i = start; i <= end; i++) {
245→                if (!pages.includes(i)) {
246→                    pages.push(i);
247→                }
248→            }
249→
250→            if (currentPage < totalPages - 3) {
251→                pages.push('...');
252→            }
253→
254→            // Always show last page
255→            if (!pages.includes(totalPages - 1)) {
256→                pages.push(totalPages - 1);
257→            }
258→        }
259→
260→        return pages;
261→    };
262→
263→    // Loading state for products
264→    if (loadingProducts) {
265→        return (
266→            <div className="container-fluid py-4">
267→                <div className="d-flex justify-content-center p-5">
268→                    <div className="spinner-border text-primary" role="status">
269→                        <span className="visually-hidden">Loading products...</span>
270→                    </div>
271→                </div>
272→            </div>
273→        );
274→    }
275→
276→    return (
277→        <div className="container-fluid py-4">
278→            <h1 className="h3 mb-4">
279→                <i className="bi bi-box-seam me-2"></i>
280→                Products Overview
281→            </h1>
282→
283→            {/* Error Alert */}
284→            {error && (
285→                <div className="alert alert-danger alert-dismissible fade show" role="alert">
286→                    <i className="bi bi-exclamation-triangle me-2"></i>
287→                    {error}
288→                    <button
289→                        type="button"
290→                        className="btn-close"
291→                        onClick={() => setError(null)}
292→                        aria-label="Close"
293→                    ></button>
294→                </div>
295→            )}
296→
297→            {/* Product selector with search */}
298→            <div className="card mb-4">
299→                <div className="card-body">
300→                    <div className="row align-items-end">
301→                        <div className="col-md-4">
302→                            <label htmlFor="productSearch" className="form-label">
303→                                Search Products
304→                            </label>
305→                            <div className="input-group">
306→                                <span className="input-group-text">
